const apiKey = global.get('INGEST_API_KEY') || 'ims-secret-key';
const incomingKey = msg.req?.headers?.['x-api-key'] || '';
if (incomingKey !== apiKey) {
    msg.res.statusCode = 401;
    msg.res.end(JSON.stringify({ error: 'Unauthorized' }));
    return null;
}

if (!msg.payload || !Array.isArray(msg.payload)) {
    msg.res.statusCode = 400;
    msg.res.end(JSON.stringify({ error: 'Payload must be a JSON array' }));
    return null;
}

msg._ldiBatch = [];
for (const item of msg.payload) {
    if (!item || !item.eqp_id) continue;
    msg._ldiBatch.push({
        eqp_id: String(item.eqp_id),
        factory: String(item.factory || ''),
        process: String(item.process || ''),
        mo: String(item.mo || ''),
        fpn: String(item.fpn || ''),
        layer_name: String(item.layer_name || ''),
        resist_dosage: Number(item.resist_dosage) || null,
        scale_x: Number(item.scale_x) || null,
        scale_y: Number(item.scale_y) || null,
        temperature: Number(item.temperature) || null,
        humidity: Number(item.humidity) || null,
        scan_speed: Number(item.scan_speed) || null,
        air_vacuum: Number(item.air_vacuum) || null,
        thickness: Number(item.thickness) || null,
        board_no: parseInt(item.board_no) || null,
        total_board: parseInt(item.total_board) || null,
        total_time: Number(item.total_time) || null,
        filmno: String(item.filmno || ''),
        board_id: String(item.board_id || ''),
        resist: Number(item.resist) || null,
        state: item.state !== false,
        scale_mode: String(item.scale_mode || ''),
        pe_1: Number(item.pe_1) || null,
        pe_2: Number(item.pe_2) || null,
        pe_3: Number(item.pe_3) || null,
        pe_4: Number(item.pe_4) || null,
        pe_5: Number(item.pe_5) || null,
        pe_6: Number(item.pe_6) || null,
        je_1: Number(item.je_1) || null,
        je_2: Number(item.je_2) || null,
        je_3: Number(item.je_3) || null,
        je_4: Number(item.je_4) || null,
        pe_setting: Number(item.pe_setting) || null,
        je_setting: Number(item.je_setting) || null,
        log_id: parseInt(item.log_id) || null
    });
}

return msg;

const err = msg.error?.message || 'Unknown error';
node.error('LDI INSERT failed: ' + err);
msg.res.statusCode = 500;
msg.res.end(JSON.stringify({ error: err }));
return null;
